const express = require('express');
const app = express();

// 1. First middleware - runs for all requests
app.use((req, res, next) => {
  console.log('1. Global middleware');
  next();
});

// 2. Route-specific middleware
app.get('/', (req, res, next) => {
  console.log('2. Route handler for /');
  next();
});

// 3. Another middleware
app.use((req, res, next) => {
  console.log('3. Another middleware');
  next();
});

// 4. Final route handler
app.get('/', (req, res) => {
  console.log('4. Final handler for /');
  res.send('Hello World');
});

